      { name: "deadline", type: "uint256" },
      { name: "lender", type: "address" },
    ],
    outputs: [{ name: "loanId", type: "uint256" }],
  },
  {
    name: "cancelLoanRequest",
    type: "function",
    stateMutability: "nonpayable",
    inputs: [{ name: "loanId", type: "uint256" }],
    outputs: [],
  },
  {
    name: "fundLoan",
    type: "function",
    stateMutability: "payable",
    inputs: [{ name: "loanId", type: "uint256" }],
    outputs: [],
  },
