   285→        for (uint256 i = 0; i < len; i++) {
   286→            if (loans[ids[i]].status == LoanStatus.Funded) activeCount++;
   287→        }
   288→
   289→        uint256[] memory result = new uint256[](activeCount);
   290→        uint256 idx = 0;
   291→        for (uint256 i = 0; i < len; i++) {
   292→            if (loans[ids[i]].status == LoanStatus.Funded) {
   293→                result[idx] = ids[i];
   294→                idx++;
   295→            }
   296→        }
   297→        return result;
   298→    }
   299→}
