   340→        vm.startPrank(borrower);
   341→        for (uint256 i = 0; i < 5; i++) {
   342→            lending.createLoanRequest(1 ether, 1.1 ether, block.timestamp + 30 days, address(0));
   343→        }
   344→        vm.stopPrank();
   345→
   346→        AgentMicrolending.LoanRequest[] memory page1 = lending.getOpenLoans(0, 2);
   347→        assertEq(page1.length, 2);
   348→        assertEq(page1[0].id, 0);
   349→        assertEq(page1[1].id, 1);
   350→
