# Using Permissionless.js with Privy Signer

## Installation

Install required packages:
```
npm i @privy-io/react-auth @privy-io/wagmi-connector permissionless viem wagmi
```

## Setup Steps

### 1. Configure Privy Provider

Initialize the Privy provider with the wagmi connector:

```javascript
import { PrivyProvider } from '@privy-io/react-auth';
import { PrivyWagmiConnector } from '@privy-io/wagmi-connector';

<PrivyProvider
  appId={"<Privy-App-Id>"}
  config={{
    embeddedWallets: {
      createOnLogin: "all-users",
    },
  }}
>
  <PrivyWagmiConnector wagmiChainsConfig={configureChainsConfig}>
    {children}
  </PrivyWagmiConnector>
</PrivyProvider>
```

### 2. Activate Privy Wallet

Retrieve and set the embedded wallet as active:

```javascript
import { useWallets } from "@privy-io/react-auth";

const { wallets } = useWallets();
const embeddedWallet = wallets.find(
  (wallet) => wallet.walletClientType === "privy"
);
```

### 3. Create Smart Account Client

```javascript
import { createSmartAccountClient } from "permissionless";
import { toSimpleSmartAccount } from "permissionless/accounts";
import { useWalletClient } from "wagmi";
import { createPublicClient, http, zeroAddress } from "viem";
import { sepolia } from "viem/chains";
import { createPimlicoClient } from "permissionless/clients/pimlico";
import { entryPoint07Address } from "viem/account-abstraction";

const { data: walletClient } = useWalletClient();

const publicClient = createPublicClient({
  chain: sepolia,
  transport: http()
});

const pimlicoUrl = `https://api.pimlico.io/v2/sepolia/rpc?apikey=<PIMLICO_API_KEY>`;

const pimlicoClient = createPimlicoClient({
  transport: http(pimlicoUrl),
  entryPoint: {
    address: entryPoint07Address,
    version: "0.7",
  }
});

const owner = embeddedWallet.getEthereumProvider();

const simpleSmartAccount = await toSimpleSmartAccount({
  owner: owner,
  client: publicClient,
  entryPoint: {
    address: entryPoint07Address,
    version: "0.7"
  }
});

const smartAccountClient = createSmartAccountClient({
  account: simpleSmartAccount,
  chain: sepolia,
  bundlerTransport: http(pimlicoUrl),
  paymaster: pimlicoClient,
  userOperation: {
    estimateFeesPerGas: async () => {
      return (await pimlicoClient.getUserOperationGasPrice()).fast;
    },
  }
});
```

### 4. Send Transaction

```javascript
const txHash = await smartAccountClient.sendTransaction({
  to: zeroAddress,
  data: "0x",
  value: BigInt(0)
});
```

## ERC-20 Paymaster Integration

Approve the paymaster for token spending:

```javascript
import { encodeFunctionData, Address } from 'viem';

const paymasterApproveData = encodeFunctionData({
  abi: ERC20ABI,
  functionName: 'approve',
  args: [paymasterAddress as Address, BigInt(paymasterValue.toString())]
});

const calls = [
  {
    to: erc20Address as Address,
    data: paymasterApproveData,
    value: BigInt(0),
  },
];
```

Send transaction with paymaster context:

```javascript
import { useSmartWallets } from '@privy-io/react-auth/smart-wallets';

const { client } = useSmartWallets();

const txHash = await client.sendTransaction({
  calls,
  paymasterContext: {
    token: erc20Address,
  },
});
```

