const USDC_DECIMALS = 6;
const LENDING_CONTRACT = "0xdDffb113C576FE87E2ceE9d38A92839b18e3e637" as const;

// Helper: convert human-readable USDC amount to smallest unit
function parseUSDC(amount: string | number): bigint {
