    10→const CELO_RPC_URL = process.env.CELO_RPC_URL || "https://forno.celo.org";
    11→
    12→function getPimlicoUrl() {
    13→  const apiKey = process.env.PIMLICO_API_KEY;
    14→  if (!apiKey) {
    15→    throw new Error("PIMLICO_API_KEY is not set");
    16→  }
    17→  return `https://api.pimlico.io/v2/celo/rpc?apikey=${apiKey}`;
    18→}
