    20→function getPrivyClient() {
    21→  const appId = process.env.PRIVY_APP_ID;
    22→  const appSecret = process.env.PRIVY_APP_SECRET;
    23→  if (!appId || !appSecret) {
    24→    throw new Error("PRIVY_APP_ID and PRIVY_APP_SECRET must be set");
    25→  }
    26→  return new PrivyClient({ appId, appSecret });
