    29→/**
    30→ * Create a gasless smart account client using a Privy server wallet.
    31→ * The Privy wallet signs via Privy's API (no private key needed locally).
    32→ * Pimlico sponsors all gas fees on Celo.
    33→ */
    34→export async function createGaslessClient(walletId: string, walletAddress: string) {
    35→  const pimlicoUrl = getPimlicoUrl();
    36→  const privy = getPrivyClient();
    37→
    38→  const publicClient = createPublicClient({
    39→    chain: celo,
    40→    transport: http(CELO_RPC_URL),
    41→  });
    42→
    43→  const pimlicoClient = createPimlicoClient({
    44→    transport: http(pimlicoUrl),
    45→    entryPoint: {
    46→      address: entryPoint07Address,
    47→      version: "0.7",
    48→    },
    49→  });
    50→
    51→  // Create a viem-compatible account backed by Privy's signing API
    52→  const owner = await createViemAccount(privy, {
